mapper.select:
SELECT COUNT(*)
  FROM TB_RESERVATION
 WHERE PET_ID = #{petId}

mapper.delete:
DELETE FROM TB_PET
 WHERE PET_ID    = #{petId}
   AND MEMBER_NO = #{memberNo}

mapper.update:
UPDATE TB_PET
   SET DEL_YN       = 'Y',
       IS_REPRESENT = 'N'
 WHERE PET_ID    = #{petId}
   AND MEMBER_NO = #{memberNo}
   AND NVL(DEL_YN, 'N') = 'N'

UPDATE TB_PET
   SET IS_REPRESENT = 'Y'
 WHERE PET_ID = (
       SELECT t.pet_id FROM (
           SELECT MIN(PET_ID) AS pet_id
             FROM TB_PET
            WHERE MEMBER_NO = #{memberNo}
              AND NVL(DEL_YN, 'N') = 'N'
       ) t
 )
